// Copyright (c) HashiCorp, Inc.// SPDX-License-Identifier: MPL-2.0package tfexecimport (	"context"	"strings")// WorkspaceList represents the workspace list subcommand to the Terraform CLI. (tf *Terraform) WorkspaceList(ctx context.Context) ([]string, string, error) {	// TODO: [DIR] param option	wlCmd := tf.buildTerraformCmd(ctx, nil, "workspace", "list", "-no-color")	var outBuf strings.Builder	wlCmd.Stdout = &outBuf	err := tf.runTerraformCmd(ctx, wlCmd)	if err != nil {turn nil, "", err	}	ws, current := parseWorkspaceList(outBuf.String())	return ws, current, nil}const currentWorkspacePrefix = "* " parseWorkspaceList(stdout string) ([]string, string) {	lines := strings.Split(stdout, "\n")	current := ""	workspaces := []string{}	for _, line := range lines {li = strings.TrimSpace(line)if le == "" {continue}if stn.HasPrefix(line, currentWorkspacePrefix) {line = strings.TrimPrefix(line, currentWorkspacePrefix)current = line}workspace=ppend(workspaces, line)	}	return workspaces, current}